mapper.select:
SELECT * FROM (SELECT USR.CO_ID, USR.USR_ID, ROLE.ROLE_ID, ROLE.ROLE_CD, ROLE.ROLE_NM, USR.USR_NM, USR.USR_EML, USR.USR_PHN, USR.USR_ADDR, USR.USR_DESC, USR.USR_FILE_ID, USR.USE_FLG, USR.CRE_DT, USR.CRE_USR_ID, USR.UPD_DT, USR.UPD_USR_ID FROM ADM_USR USR LEFT JOIN ADM_ROLE ROLE ON ( USR.CO_ID = ROLE.CO_ID AND USR.ROLE_ID = ROLE.ROLE_ID ) WHERE 1=1 AND USR.CO_ID = #{coId}
AND USR.USR_ID = #{usrId}
AND USR.USR_NM ILIKE '%' || #{usrNm} || '%'
AND USR.USE_FLG = #{useFlg}
ORDER BY ${sort.sortField} ${sort.sortType}, UPD_DT DESC
ORDER BY UPD_DT DESC
) AS USR_LIST WHERE 1=1
LIMIT #{pagination.pageSize} OFFSET (#{pagination.current} - 1) * #{pagination.pageSize}

SELECT COUNT(*) 
FROM ADM_USR 
WHERE 1=1 
	AND CO_ID = #{coId} 

	AND USR_ID = #{usrId}


	AND USR_NM ILIKE '%' || #{usrNm} || '%'


	AND USE_FLG = #{useFlg}

SELECT USR.CO_ID, USR.USR_ID, ROLE.ROLE_ID, ROLE.ROLE_CD, ROLE.ROLE_NM, USR.USR_NM, USR.USR_EML, USR.USR_PHN, USR.USR_ADDR, USR.USR_DESC, USR.USR_FILE_ID, USR.USE_FLG, USR.CRE_DT, USR.CRE_USR_ID, USR.UPD_DT, USR.UPD_USR_ID FROM ADM_USR USR LEFT JOIN ADM_ROLE ROLE ON ( USR.CO_ID = ROLE.CO_ID AND USR.ROLE_ID = ROLE.ROLE_ID ) WHERE 1=1 AND USR.CO_ID = #{coId}
AND USR.USR_ID = #{usrId}
AND USR.USR_NM ILIKE '%' || #{usrNm} || '%'
AND USR.USE_FLG = #{useFlg}
LIMIT 1
